import { useEffect, useState } from "react";
import { Link, useParams, useSearchParams } from "react-router-dom";

function ListeArtisans() {
  const { categorie } = useParams();
  const [searchParams] = useSearchParams();

  const recherche = searchParams.get("recherche");

  const [artisans, setArtisans] = useState([]);

  useEffect(() => {
    let url = "http://localhost:3080/api/artisans";

    if (categorie) {
      url = `http://localhost:3080/api/artisans/categorie/${categorie}`;
    }

    fetch(url)
      .then((res) => res.json())
      .then((data) => {
        let resultats = data;

        if (recherche) {
          resultats = data.filter((artisan) =>
            artisan.Nom.toLowerCase().includes(recherche.toLowerCase())
          );
        }

        setArtisans(resultats);
      })
      .catch((error) => {
        console.error(error);
      });
  }, [categorie, recherche]);

  return (
    <main className="container py-5">
      <h1 className="mb-4">Liste des artisans</h1>

      <div className="row">
        {artisans.map((artisan) => {
          const note = Math.round(Number(artisan.Note));

          return (
            <div className="col-12 col-md-6 col-lg-4 mb-4" key={artisan.Id_artisan}>
              <Link
                to={`/artisans/${artisan.Id_artisan}`}
                className="text-decoration-none text-dark"
              >
                <div className="card h-100 shadow-sm">
                  <div className="card-body">
                    <h2 className="h5 card-title">{artisan.Nom}</h2>

                    <p className="mb-2">
                      {"★".repeat(note)}
                      {"☆".repeat(5 - note)}
                    </p>

                    <p className="mb-2">
                      <strong>Spécialité :</strong>{" "}
                      {artisan.Specialite?.Nom || "Non renseignée"}
                    </p>

                    <p className="mb-0">
                      <strong>Ville :</strong> {artisan.Ville}
                    </p>
                  </div>
                </div>
              </Link>
            </div>
          );
        })}
      </div>
    </main>
  );
}

export default ListeArtisans;
